/**
 * vocabulary — every word from the shared, standards-grounded scheme. Whatever
 * the language, the WORDS are written only from one vocabulary (./words.ts: the
 * English dictionary ∪ schema.org ∪ standard codes ∪ established domain terms,
 * generated by scripts/vocab-gen.mjs). An atom is GROUNDED iff it is a vocabulary
 * root or COMPOSES from roots (budgetvariance → budget+variance); an ungrounded
 * atom is ENTROPY — a typo and a forgery are the same thing, a word from outside
 * the scheme. The audit drives that entropy to ZERO and, for any stray, COMPUTES
 * the zero-entropy solution: the nearest vocabulary word, or the decomposition.
 *
 *   tsx src/vocabulary/index.ts
 *
 * @standard ISO 25964 / SKOS — a controlled vocabulary: terms from one shared scheme
 * @audit computed over the live uuid-matrix atoms against ./words.ts; never hand-asserted
 * @see ./words.ts (the generated vocabulary) -- ./test.ts (the 0-entropy gate) -- ../trinity (md-purity) -- ../unavoidable
 */
import { UUID_MATRIX_NODES as N } from '@/uuid/matrix'
import { SHARED_VOCABULARY as V } from './words'

const sing = (w: string): string =>
  w.endsWith('ies') && w.length > 4 ? w.slice(0, -3) + 'y'
  : /(ses|xes|zes|ches|shes)$/.test(w) ? w.slice(0, -2)
  : w.endsWith('s') && !w.endsWith('ss') ? w.slice(0, -1)
  : w
const known = (w: string): boolean => V.has(w) || V.has(sing(w))

/** The vocabulary-root decomposition of a word, or null if it cannot be grounded. */
export const decompose = (w: string): string[] | null => {
  if (known(w)) return [w]
  for (let i = w.length - 3; i >= 3; i--) {
    // longest known prefix first (budget+variance, not bud+get)
    if (known(w.slice(0, i))) {
      const rest = decompose(w.slice(i))
      if (rest) return [w.slice(0, i), ...rest]
    }
  }
  return null
}

/** An atom is grounded iff it is a vocabulary root or composes from roots. */
export const isGrounded = (atom: string): boolean => decompose(atom) !== null

/** Levenshtein edit distance — for the nearest-vocabulary-word suggestion. */
export const editDistance = (a: string, b: string): number => {
  const d: number[][] = Array.from({ length: a.length + 1 }, () => Array(b.length + 1).fill(0))
  for (let i = 0; i <= a.length; i++) d[i][0] = i
  for (let j = 0; j <= b.length; j++) d[0][j] = j
  for (let i = 1; i <= a.length; i++)
    for (let j = 1; j <= b.length; j++)
      d[i][j] = Math.min(d[i - 1][j] + 1, d[i][j - 1] + 1, d[i - 1][j - 1] + (a[i - 1] === b[j - 1] ? 0 : 1))
  return d[a.length][b.length]
}

/** The COMPUTED zero-entropy solution for an ungrounded word — ground it the cheapest way. */
export const suggest = (atom: string): string => {
  let best = ''
  let bestD = 3
  for (const w of V) {
    if (Math.abs(w.length - atom.length) >= bestD) continue
    const d = editDistance(atom, w)
    if (d < bestD) { bestD = d; best = w }
  }
  if (best) return `→ "${best}" (nearest vocabulary word, edit distance ${bestD}) — rename/merge to ground it`
  const parts = decompose(atom)
  if (parts && parts.length > 1) return `→ split into ${parts.join('/')} (path=type) — compose from vocabulary roots`
  return '→ extend the shared vocabulary (vocab-gen) or ground it in a standard'
}

export type VocabularyAudit = { atoms: number; grounded: number; flagged: { atom: string; suggestion: string }[] }

/** Audit atom names against the shared vocabulary — flagged carries the computed solution. */
export const audit = (atomNames: Iterable<string>): VocabularyAudit => {
  const set = [...new Set(atomNames)].sort()
  const flagged = set.filter((a) => !isGrounded(a)).map((a) => ({ atom: a, suggestion: suggest(a) }))
  return { atoms: set.length, grounded: set.length - flagged.length, flagged }
}

/** The live audit over the corpus's own atoms (the uuid-matrix). */
export const auraVocabulary = (): VocabularyAudit => audit(N.map((n) => n.atom))

if (import.meta.url === 'file://' + process.argv[1]) {
  const r = auraVocabulary()
  console.log(`vocabulary — ${r.atoms} atoms · grounded ${r.grounded} · entropy ${r.flagged.length}`)
  for (const f of r.flagged) console.log(`  ✗ ${f.atom}  ${f.suggestion}`)
  if (!r.flagged.length) console.log('  ✓ zero entropy — every word from the shared vocabulary')
}
